import { useEffect, useRef, useState } from "react"
import { addPropertyControls } from "framer"

const MASCOT_SRC =
    "data:image/png;base64,"

const IDLE_MESSAGES = ["hire this guy"]
const HOVER_MESSAGES = ["hi", "gm gm", "what's up"]
const SIZE = 50

export default function Mascot() {
    const containerRef = useRef<HTMLDivElement>(null)
    const mascotRef = useRef<HTMLDivElement>(null)
    const imgRef = useRef<HTMLImageElement>(null)
    const s = useRef({ pos: 0, dir: 1 })
    const rafRef = useRef(0)
    const hoveredRef = useRef(false)
    const lastHoverBubbleRef = useRef(0)
    const idleTimerRef = useRef<any>(null)

    const [bubble, setBubble] = useState<string | null>(null)

    // Movement + bob loop — all DOM writes, zero re-renders
    useEffect(() => {
        const animate = (time: number) => {
            const w = containerRef.current
                ? containerRef.current.offsetWidth
                : 400
            const max = w - SIZE
            s.current.pos += s.current.dir * 0.8
            if (s.current.pos >= max) {
                s.current.pos = max
                s.current.dir = -1
                if (imgRef.current)
                    imgRef.current.style.transform = "scaleX(-1)"
            } else if (s.current.pos <= 0) {
                s.current.pos = 0
                s.current.dir = 1
                if (imgRef.current) imgRef.current.style.transform = "scaleX(1)"
            }
            if (mascotRef.current) {
                mascotRef.current.style.left = s.current.pos + "px"
                mascotRef.current.style.bottom = Math.sin(time / 300) * 4 + "px"
            }
            rafRef.current = requestAnimationFrame(animate)
        }
        rafRef.current = requestAnimationFrame(animate)
        return () => cancelAnimationFrame(rafRef.current)
    }, [])

    // Idle bubble: fires every 10 seconds, skips if hovered
    useEffect(() => {
        const schedule = () => {
            idleTimerRef.current = setTimeout(() => {
                if (!hoveredRef.current) {
                    const msg =
                        IDLE_MESSAGES[
                            Math.floor(Math.random() * IDLE_MESSAGES.length)
                        ]
                    setBubble(msg)
                    setTimeout(() => setBubble(null), 2500)
                }
                schedule()
            }, 10000)
        }
        schedule()
        return () => clearTimeout(idleTimerRef.current)
    }, [])

    const handleMouseEnter = () => {
        hoveredRef.current = true
        s.current.dir *= -1
        if (imgRef.current) {
            imgRef.current.style.transform =
                s.current.dir === -1 ? "scaleX(-1)" : "scaleX(1)"
        }
        // Hover bubble: max once per 10 seconds
        const now = Date.now()
        if (now - lastHoverBubbleRef.current >= 10000) {
            lastHoverBubbleRef.current = now
            const msg =
                HOVER_MESSAGES[
                    Math.floor(Math.random() * HOVER_MESSAGES.length)
                ]
            setBubble(msg)
            setTimeout(() => setBubble(null), 2500)
        }
    }

    const handleMouseLeave = () => {
        hoveredRef.current = false
    }

    return (
        <div
            ref={containerRef}
            style={{
                position: "relative",
                width: "100%",
                height: "100%",
                pointerEvents: "none",
            }}
        >
            <div
                ref={mascotRef}
                onMouseEnter={handleMouseEnter}
                onMouseLeave={handleMouseLeave}
                style={{
                    position: "absolute",
                    bottom: 0,
                    left: 0,
                    width: SIZE,
                    height: SIZE,
                    pointerEvents: "all",
                    cursor: "default",
                    userSelect: "none",
                }}
            >
                {bubble !== null && (
                    <div
                        style={{
                            position: "absolute",
                            bottom: SIZE + 8,
                            left: "50%",
                            transform: "translateX(-50%)",
                            background: "#ffffff",
                            color: "#111111",
                            padding: "5px 12px",
                            borderRadius: 999,
                            fontSize: 11,
                            fontWeight: 600,
                            fontFamily: "system-ui, sans-serif",
                            whiteSpace: "nowrap",
                            boxShadow: "0 2px 8px rgba(0,0,0,0.15)",
                            pointerEvents: "none",
                            lineHeight: "1.4",
                        }}
                    >
                        {bubble}
                        <div
                            style={{
                                position: "absolute",
                                bottom: -6,
                                left: "50%",
                                transform: "translateX(-50%)",
                                width: 0,
                                height: 0,
                                borderLeft: "6px solid transparent",
                                borderRight: "6px solid transparent",
                                borderTop: "6px solid #ffffff",
                            }}
                        />
                    </div>
                )}
                <img
                    ref={imgRef}
                    src={MASCOT_SRC}
                    width={SIZE}
                    height={SIZE}
                    draggable={false}
                    style={{
                        display: "block",
                        objectFit: "contain",
                        transform: "scaleX(1)",
                        transition: "transform 0.12s ease",
                        pointerEvents: "none",
                    }}
                />
            </div>
        </div>
    )
}

addPropertyControls(Mascot, {})
